def require_invoice_ownership(f):
    @wraps(f)
    def decorated_function(invoice_id, *args, **kwargs):
        # Retrieve invoice from database
        invoice = INVOICES_DB.get(invoice_id)
        
        # Check if invoice exists
        if not invoice:
            return jsonify({'error': 'Invoice not found'}), 404
        
        # CRITICAL: Verify that the authenticated user owns this invoice
        # This prevents users from accessing other users' invoices
        if invoice['user_id'] != g.user['id']:
            # Don't reveal whether invoice exists for security
            return jsonify({'error': 'Invoice not found'}), 404
        
        # Pass the validated invoice to the route handler
        return f(invoice_id, invoice, *args, **kwargs)
    
    return decorated_function

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
@require_invoice_ownership
def download_invoice(invoice_id, invoice):
    """
    Download invoice PDF with proper authorization checks.
    
    Security measures implemented:
    1. Object-level authorization: Verifies user owns the invoice
    2. Tenant scoping: Only returns invoices belonging to authenticated user
    3. Input validation: invoice_id is validated as integer by Flask
    4. Existence check: Returns 404 if invoice doesn't exist
    5. Consistent error messages: Doesn't leak information about other invoices
    """
    
    try:
        # Construct safe file path
        # In production, use secure file storage (S3, Azure Blob, etc.)
        invoice_filename = invoice['filename']
        file_path = os.path.join('invoices', str(invoice['user_id']), invoice_filename)
        
        # Additional security: Validate file path to prevent directory traversal
        file_path = os.path.normpath(file_path)
        if not file_path.startswith('invoices/'):
            return jsonify({'error': 'Invalid file path'}), 400
        
        # Check if file exists
        if not os.path.exists(file_path):
            # Log this for investigation - file should exist if in DB
            app.logger.error(f"Invoice file missing: {file_path}")
            return jsonify({'error': 'Invoice file not available'}), 500
        
        # Return the PDF file
        return send_file(
            file_path,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=invoice_filename
        )
        
    except Exception as e:
        app.logger.error(f"Error downloading invoice {invoice_id}: {str(e)}")
        return jsonify({'error': 'Failed to download invoice'}), 500

@app.route('/api/invoices', methods=['GET'])
def list_invoices():
    """
    List all invoices for the authenticated user.
    Demonstrates proper tenant scoping.
    """
    user_id = g.user['id']
    
    # Filter invoices to only show those belonging to the authenticated user
    user_invoices = [
        {
            'id': inv['id'],
            'filename': inv['filename'],
            'amount': inv['amount']
            # Note: user_id is NOT exposed to prevent information leakage
        }
        for inv in INVOICES_DB.values()
        if inv['user_id'] == user_id
    ]
    
    return jsonify({'invoices': user_invoices}), 200

